import{_ as e,o as a,c as i,a2 as d}from"./chunks/framework.y1bVONfd.js";const m=JSON.parse('{"title":"Animation System","description":"","frontmatter":{},"headers":[],"relativePath":"builder/animations.md","filePath":"builder/animations.md"}'),n={name:"builder/animations.md"};function o(l,t,r,s,c,h){return a(),i("div",null,[...t[0]||(t[0]=[d('<h1 id="animation-system" tabindex="-1">Animation System <a class="header-anchor" href="#animation-system" aria-label="Permalink to &quot;Animation System&quot;">​</a></h1><p>WebBeagle uses a centralized animation engine with <code>data-animate-*</code> attributes. It works on both the builder canvas and published pages.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Containers</strong> get a <code>data-animate</code> attribute (e.g., <code>data-animate=&quot;fade-up&quot;</code>)</li><li><strong>Children</strong> get <code>data-animate-item</code> attributes</li><li>The engine applies staggered delays and triggers via IntersectionObserver</li><li>Single elements without children animate themselves</li></ol><h2 id="using-the-animation-panel" tabindex="-1">Using the Animation Panel <a class="header-anchor" href="#using-the-animation-panel" aria-label="Permalink to &quot;Using the Animation Panel&quot;">​</a></h2><h3 id="opening-the-panel" tabindex="-1">Opening the Panel <a class="header-anchor" href="#opening-the-panel" aria-label="Permalink to &quot;Opening the Panel&quot;">​</a></h3><p>Click the <strong>🎬 Animate</strong> button in the toolbar. The panel slides in from the right.</p><div class="warning custom-block"><p class="custom-block-title">Style Manager</p><p>The Animation panel covers the Style Manager. Close it with the 🎬 button when you want to style elements.</p></div><h3 id="enabling-animation" tabindex="-1">Enabling Animation <a class="header-anchor" href="#enabling-animation" aria-label="Permalink to &quot;Enabling Animation&quot;">​</a></h3><ol><li>Select an element (section, card, heading, or any element)</li><li>Open the Animation panel</li><li>Click the <strong>OFF → ON</strong> toggle</li><li>Choose a preset</li></ol><h3 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Range</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><strong>Preset</strong></td><td>fade-up / fade-in / slide-left / slide-right / zoom-in</td><td>fade-up</td><td>Animation type</td></tr><tr><td><strong>Stagger</strong></td><td>0–500ms</td><td>120ms</td><td>Delay between each child</td></tr><tr><td><strong>Duration</strong></td><td>200–3000ms</td><td>800ms</td><td>How long each animation takes</td></tr><tr><td><strong>Initial Opacity</strong></td><td>0–1</td><td>0</td><td>Starting opacity</td></tr><tr><td><strong>Trigger</strong></td><td>scroll / load</td><td>scroll</td><td>When animation fires</td></tr></tbody></table><h3 id="staggering-children" tabindex="-1">Staggering Children <a class="header-anchor" href="#staggering-children" aria-label="Permalink to &quot;Staggering Children&quot;">​</a></h3><p>Click <strong>✨ Stagger All Children</strong> to automatically tag:</p><ul><li>Grid children (<code>.services-grid</code>, <code>.testimonials-grid</code>, <code>.steps-grid</code>)</li><li>Direct children of the selected element</li><li>The element itself (if no children — for standalone items like headings)</li></ul><h3 id="animating-a-single-element" tabindex="-1">Animating a Single Element <a class="header-anchor" href="#animating-a-single-element" aria-label="Permalink to &quot;Animating a Single Element&quot;">​</a></h3><ol><li>Select the element (e.g., a heading)</li><li>Open 🎬 Animate</li><li>Click ON → choose preset</li><li>Click ✨ Stagger All Children</li><li>The engine detects no children and animates the element itself</li></ol><h2 id="data-attributes" tabindex="-1">Data Attributes <a class="header-anchor" href="#data-attributes" aria-label="Permalink to &quot;Data Attributes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Attribute</th><th>Value</th><th>Example</th></tr></thead><tbody><tr><td><code>data-animate</code></td><td>fade-up, fade-in, slide-left, slide-right, zoom-in</td><td><code>data-animate=&quot;fade-up&quot;</code></td></tr><tr><td><code>data-stagger</code></td><td>milliseconds</td><td><code>data-stagger=&quot;150&quot;</code></td></tr><tr><td><code>data-duration</code></td><td>milliseconds</td><td><code>data-duration=&quot;1000&quot;</code></td></tr><tr><td><code>data-easing</code></td><td>CSS easing function</td><td><code>data-easing=&quot;cubic-bezier(0.16,1,0.3,1)&quot;</code></td></tr><tr><td><code>data-initial-opacity</code></td><td>0–1</td><td><code>data-initial-opacity=&quot;0&quot;</code></td></tr><tr><td><code>data-offset</code></td><td>pixels</td><td><code>data-offset=&quot;60&quot;</code></td></tr><tr><td><code>data-trigger</code></td><td>scroll or load</td><td><code>data-trigger=&quot;load&quot;</code></td></tr><tr><td><code>data-animate-item</code></td><td>(no value)</td><td><code>data-animate-item</code></td></tr></tbody></table><h2 id="published-pages" tabindex="-1">Published Pages <a class="header-anchor" href="#published-pages" aria-label="Permalink to &quot;Published Pages&quot;">​</a></h2><p>The animation system is injected into every published page via <code>_render_preview()</code>. The engine:</p><ul><li>Processes all <code>[data-animate]</code> containers</li><li>Adds <code>.wb-animated</code> classes to items</li><li>Sets CSS custom properties for delay, duration, opacity</li><li>Triggers via IntersectionObserver on scroll</li><li>Supports <code>data-trigger=&quot;load&quot;</code> for immediate animation</li></ul><h2 id="legacy-support" tabindex="-1">Legacy Support <a class="header-anchor" href="#legacy-support" aria-label="Permalink to &quot;Legacy Support&quot;">​</a></h2><p>The engine also handles legacy <code>.reveal</code> classes (used in the how-it-works section). These are triggered by a separate IntersectionObserver with staggered transition delays.</p>',24)])])}const u=e(n,[["render",o]]);export{m as __pageData,u as default};
